     /// Matrix multiplication.
     pub fn matmul(&self, other: &Tensor) -> Result<Tensor> {
+        let self_ndim = self.shape().len();
+        let other_ndim = other.shape().len();
+        
+        match (self_ndim, other_ndim) {
+            (2, 2) => {
+                // existing 2D implementation
+                Ok(Tensor::default())
+            }
+            (3, 3) => {
+                // new 3D batched implementation
+                Ok(Tensor::default())
+            }
+            _ => Err("unsupported tensor shapes for matmul".into())
+        }
     }
